func transcriptEventClass(kind string) string {
	switch kind {
	case "reasoning":
		return "text-gray-500"
	case "tool":
		return "text-indigo-400"
	case "text":
		return "text-green-300"
	case "stderr":
		return "text-red-400"
	case "step", "event", "raw":
		return "text-gray-400"
	default:
		return "text-gray-400"
	}
}

func openCodeLifecycleLabel(state string) string {
	switch state {
	case "active_streaming":
		return "streaming"
	case "active_output":
		return "output captured"
	case "running_no_output":
		return "starting"
	case "waiting_output":
		return "waiting for output"
	case "waiting_response":
		return "waiting for response"
	case "stale_output":
		return "stale output"
	case "stale_timeout":
		return "timed out"
	case "completed":
		return "completed"
	case "completed_without_result":
		return "completed without result"
	case "failed":
		return "failed"
	default:
		return "monitoring"
	}
}

func openCodeLifecycleDescription(previews RunPreviews) string {
	switch previews.OpenCodeLifecycleState {
	case "active_streaming":
		return "OpenCode is running and Relay is receiving streamed chunks."
	case "active_output":
		return "OpenCode is running and output artifacts are being updated."
	case "running_no_output":
		return "OpenCode is still inside the startup grace period and has not emitted output yet."
	case "waiting_output":
		return "OpenCode is running, but Relay has not seen output yet."
	case "waiting_response":
		return "OpenCode has gone quiet and may be waiting on a final response. Stop Waiting and Inspect Git Diff if the repo changes already look complete."
	case "stale_output":
		return "OpenCode stopped emitting output and may need recovery."
	case "stale_timeout":
		return "OpenCode exceeded the timeout window and may need recovery."
	case "completed":
		return "OpenCode finished and Relay will show the parsed result."
	case "completed_without_result":
		return "OpenCode finished, but Relay did not find a final DONE/BLOCKED result. Review the logs and inspect git diff before continuing."
	case "failed":
		return "OpenCode ended with a failure; review logs and artifacts."
	default:
		return "Relay is monitoring the execution."
	}
}

func openCodeTranscriptTail(events []OpenCodeTranscriptEventView, n int) []OpenCodeTranscriptEventView {
	if len(events) == 0 {
		return nil
	}
	if len(events) <= n {
		return events
	}
	return events[len(events)-n:]
}

func openCodeTrimEventText(text string, max int) string {
	if max <= 0 || len(text) <= max {
		return text
	}
	return text[:max] + "..."
}

func openCodeActivityLabel(kind string) string {
	switch kind {
	case "reasoning":
		return "agent internal update"
	case "tool":
		return "tool call"
	case "text":
		return "assistant output"
	case "stderr":
		return "stderr"
	case "step":
		return "step update"
	case "event":
		return "event"
	case "raw":
		return "raw output"
	default:
		return kind
	}
}

func openCodeCurrentActivity(events []OpenCodeTranscriptEventView) string {
	if len(events) == 0 {
		return ""
	}
	last := events[len(events)-1]
	label := openCodeActivityLabel(last.Kind)
	if label == "" {
		label = "activity"
	}
	detail := openCodeTrimEventText(last.Text, 120)
	if detail == "" {
		return label
	}
	return label + ": " + detail
}

