func validationProgressFinished(previews RunPreviews) bool {
	return previews.HasValidationProgress && (previews.ValidationProgressPreview.Status == "pass" || previews.ValidationProgressPreview.Status == "fail")
}

func validationProgressElapsed(progress ValidationProgressPreview) string {
	startedAt, err := time.Parse(time.RFC3339, progress.StartedAt)
	if err != nil || startedAt.IsZero() {
		return ""
	}
	endValue := progress.UpdatedAt
	if progress.FinishedAt != "" {
		endValue = progress.FinishedAt
	}
	if endValue == "" {
		endValue = time.Now().UTC().Format(time.RFC3339)
	}
	endedAt, err := time.Parse(time.RFC3339, endValue)
	if err != nil || endedAt.IsZero() {
		return ""
	}
	if endedAt.Before(startedAt) {
		return ""
	}
	return formatDuration(endedAt.Sub(startedAt).Milliseconds())
}

func validationProgressCommandDuration(cmd ValidationProgressCommandView) string {
	if cmd.DurationMs > 0 {
		return formatDuration(cmd.DurationMs)
	}
	if cmd.Status == "running" && cmd.StartedAt != "" {
		startedAt, err := time.Parse(time.RFC3339, cmd.StartedAt)
		if err != nil || startedAt.IsZero() {
			return ""
		}
		elapsed := time.Since(startedAt.UTC()).Milliseconds()
		if elapsed < 0 {
			return ""
		}
		return formatDuration(elapsed)
	}
	if cmd.StartedAt != "" && cmd.CompletedAt != "" {
		startedAt, err := time.Parse(time.RFC3339, cmd.StartedAt)
		if err != nil || startedAt.IsZero() {
			return ""
		}
		completedAt, err := time.Parse(time.RFC3339, cmd.CompletedAt)
		if err != nil || completedAt.IsZero() {
			return ""
		}
		if completedAt.Before(startedAt) {
			return ""
		}
		return formatDuration(completedAt.Sub(startedAt).Milliseconds())
	}
	return ""
}

func relayValidationUIStateFor(hasAgentResult bool, hasValidationCommands bool, hasValidationRun bool) relayValidationUIState {
	if hasValidationRun {
		return relayValidationCompleted
	}
	if !hasAgentResult {
		return relayValidationNoResult
	}
	if !hasValidationCommands {
		return relayValidationNoCommands
	}
	return relayValidationReady
}

